<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8" />
<meta name="viewport" content="width=device-width,initial-scale=1" />
<title>Sort Comparison: Bubble vs Quick vs Merge</title>
<style>
  :root{
    --bg:#0f1724;
    --panel:#0b1220;
    --accent:#60a5fa;
    --muted:#94a3b8;
    --good:#34d399;
    --bad:#fb7185;
    color-scheme: dark;
  }
  html,body{height:100%;margin:0;background:linear-gradient(180deg,#071127 0%, #071723 100%);font-family:Inter,ui-sans-serif,system-ui,-apple-system,"Segoe UI",Roboto,"Helvetica Neue",Arial; color: #e6eef8;}
  .wrap{max-width:1200px;margin:18px auto;padding:18px;box-sizing:border-box;}
  h1{margin:0 0 8px;font-weight:600;font-size:20px;color:var(--accent);}
  p.lead{margin:0 0 16px;color:var(--muted);}
  .controls{display:flex;gap:12px;flex-wrap:wrap;align-items:center;margin-bottom:12px;}
  .controls > *{background:var(--panel);border:1px solid rgba(255,255,255,0.04);padding:8px;border-radius:8px;color:inherit;}
  button{cursor:pointer;}
  .grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;}
  .panel{background:linear-gradient(180deg,rgba(255,255,255,0.02),transparent);padding:12px;border-radius:10px;border:1px solid rgba(255,255,255,0.03);min-height:300px;display:flex;flex-direction:column;}
  .panel h3{margin:0 0 8px;font-size:14px;color:var(--accent);}
  .canvas{flex:1;display:flex;align-items:end;gap:2px;padding:8px;border-radius:6px;background:linear-gradient(180deg, rgba(255,255,255,0.01), transparent);overflow:hidden;}
  .bar{background:linear-gradient(180deg,#60a5fa,#3b82f6);flex:1;border-radius:3px 3px 0 0;transition:background 120ms linear;}
  .bar.current{background:linear-gradient(180deg,#fb7185,#ef4444);}
  .bar.compare{background:linear-gradient(180deg,#f59e0b,#f97316);}
  .bar.sorted{background:linear-gradient(180deg,#34d399,#10b981);}
  .stats{display:flex;gap:12px;margin-top:8px;align-items:center;flex-wrap:wrap;}
  .stat{font-size:12px;color:var(--muted);display:flex;gap:6px;align-items:center;}
  .small{font-size:12px;color:var(--muted);}
  .explain{font-size:12px;margin-top:8px;color:var(--muted);line-height:1.4}
  .footer{font-size:12px;color:var(--muted);margin-top:12px;}
  input[type=range]{width:160px;}
  .seed-input{width:140px;}
  @media (max-width:900px){
    .grid{grid-template-columns:1fr; }
  }
</style>
</head>
<body>
<div class="wrap">
  <h1>Sorting Algorithm Comparison — Bubble Sort vs Quick Sort vs Merge Sort</h1>
  <p class="lead">Watch the same array being sorted side-by-side. Step counters show comparisons and writes (swaps/assignments). Use controls to change size and speed, and to randomize or choose nearly-sorted data.</p>

  <div class="controls">
    <label>Array size:
      <input id="size" type="range" min="10" max="120" value="50">
      <span id="sizeVal">50</span>
    </label>
    <label>Speed:
      <input id="speed" type="range" min="1" max="200" value="60">
      <span id="speedVal">60 ms</span>
    </label>
    <label>Preset:
      <select id="preset">
        <option value="random">Random</option>
        <option value="reversed">Reversed</option>
        <option value="nearly">Nearly sorted</option>
        <option value="fewUnique">Few unique</option>
      </select>
    </label>
    <button id="start">Start</button>
    <button id="pause">Pause</button>
    <button id="reset">Reset</button>
    <button id="step">Step</button>
    <label>Seed:
      <input id="seed" class="seed-input" placeholder="optional number">
    </label>
  </div>

  <div class="grid">
    <div class="panel" id="panel-bubble">
      <h3>Bubble Sort</h3>
      <div class="canvas" id="canvas-bubble"></div>
      <div class="stats">
        <div class="stat">Comparisons: <span id="bubble-comp">0</span></div>
        <div class="stat">Writes: <span id="bubble-write">0</span></div>
        <div class="stat">Pass: <span id="bubble-pass">0</span></div>
      </div>
      <div class="explain">
        Worst/Avg: O(n^2). Best (already sorted): O(n). Bubble sort repeatedly swaps adjacent elements — simple but inefficient for large arrays.
      </div>
    </div>

    <div class="panel" id="panel-quick">
      <h3>Quick Sort (Lomuto)</h3>
      <div class="canvas" id="canvas-quick"></div>
      <div class="stats">
        <div class="stat">Comparisons: <span id="quick-comp">0</span></div>
        <div class="stat">Writes: <span id="quick-write">0</span></div>
        <div class="stat">Active recursions: <span id="quick-rec">0</span></div>
      </div>
      <div class="explain">
        Average: O(n log n). Worst: O(n^2) (bad pivots). Quick sort partitioning is efficient in practice; speed depends on pivot choice.
      </div>
    </div>

    <div class="panel" id="panel-merge">
      <h3>Merge Sort</h3>
      <div class="canvas" id="canvas-merge"></div>
      <div class="stats">
        <div class="stat">Comparisons: <span id="merge-comp">0</span></div>
        <div class="stat">Writes: <span id="merge-write">0</span></div>
        <div class="stat">Active merges: <span id="merge-act">0</span></div>
      </div>
      <div class="explain">
        Worst/Avg/Best: O(n log n). Merge sort is stable and guarantees n log n but requires extra space for merging.
      </div>
    </div>
  </div>

  <div class="footer">
    Tip: Try "Nearly sorted" with small size — bubble sort can be efficient in best cases, but for general large random arrays, Quick and Merge are far faster.
  </div>
</div>

<script>
/* Self-contained sorting visualizer. No external libs. 
   Approximates step-by-step operations and animates three algorithms on identical data.
*/

(function(){
  // Utilities
  function rng(seed){
    // simple LCG
    let s = seed >>> 0;
    return function(){
      s = (1664525 * s + 1013904223) >>> 0;
      return s / 4294967296;
    };
  }

  function createArray(n, preset, rand){
    let a = [];
    if(preset === 'reversed'){
      for(let i=0;i<n;i++) a.push(n-i);
    } else if(preset === 'nearly'){
      for(let i=1;i<=n;i++) a.push(i);
      // shuffle a small fraction
      let swaps = Math.max(1, Math.floor(n*0.05));
      for(let i=0;i<swaps;i++){
        let x = Math.floor(rand()*n), y = Math.floor(rand()*n);
        [a[x],a[y]] = [a[y],a[x]];
      }
    } else if(preset === 'fewUnique'){
      let uniques = Math.max(2, Math.floor(n*0.1));
      for(let i=0;i<n;i++) a.push( Math.floor(rand()*uniques)+1 );
    } else {
      for(let i=0;i<n;i++) a.push(Math.floor(rand()*n)+1);
    }
    return a;
  }

  // DOM
  const sizeSlider = document.getElementById('size');
  const sizeVal = document.getElementById('sizeVal');
  const speedSlider = document.getElementById('speed');
  const speedVal = document.getElementById('speedVal');
  const preset = document.getElementById('preset');
  const startBtn = document.getElementById('start');
  const pauseBtn = document.getElementById('pause');
  const resetBtn = document.getElementById('reset');
  const stepBtn = document.getElementById('step');
  const seedInput = document.getElementById('seed');

  sizeVal.textContent = sizeSlider.value;
  speedVal.textContent = speedSlider.value + " ms";

  sizeSlider.addEventListener('input', ()=> sizeVal.textContent = sizeSlider.value );
  speedSlider.addEventListener('input', ()=> speedVal.textContent = speedSlider.value + " ms" );

  // Canvas elements
  const canvasBubble = document.getElementById('canvas-bubble');
  const canvasQuick = document.getElementById('canvas-quick');
  const canvasMerge = document.getElementById('canvas-merge');

  // Stats elements
  const bComp = document.getElementById('bubble-comp');
  const bWrite = document.getElementById('bubble-write');
  const bPass = document.getElementById('bubble-pass');

  const qComp = document.getElementById('quick-comp');
  const qWrite = document.getElementById('quick-write');
  const qRec = document.getElementById('quick-rec');

  const mComp = document.getElementById('merge-comp');
  const mWrite = document.getElementById('merge-write');
  const mAct = document.getElementById('merge-act');

  // State
  let baseArray = [];
  let running = false;
  let auto = null;
  let speed = parseInt(speedSlider.value,10);
  let stepMode = false;
  let stepRequested = false;

  function mkBars(container, array){
    container.innerHTML = '';
    const n = array.length;
    for(let i=0;i<n;i++){
      const d = document.createElement('div');
      d.className = 'bar';
      d.style.height = (array[i]/(Math.max(...array)||1))*100 + '%';
      d.dataset.index = i;
      container.appendChild(d);
    }
    return container.children;
  }

  function updateBars(bars, array, highlights={}){
    const n = array.length;
    for(let i=0;i<n;i++){
      const el = bars[i];
      el.style.height = (array[i]/(Math.max(...array)||1))*100 + '%';
      el.classList.remove('current','compare','sorted');
    }
    if(highlights.current) highlights.current.forEach(i=>{ if(bars[i]) bars[i].classList.add('current'); });
    if(highlights.compare) highlights.compare.forEach(i=>{ if(bars[i]) bars[i].classList.add('compare'); });
    if(highlights.sorted) highlights.sorted.forEach(i=>{ if(bars[i]) bars[i].classList.add('sorted'); });
  }

  // Algorithms: each produces a generator that yields steps describing comparisons/writes/highlights
  // Step format examples:
  // {type:'compare',i,j}, {type:'swap',i,j}, {type:'write',i,value}, {type:'markSorted',i}, {type:'pass',count}
  function* bubbleSort(a){
    let n = a.length;
    let pass = 0;
    for(let i=0;i<n;i++){
      let swapped = false;
      pass++;
      yield {type:'pass',pass};
      for(let j=0;j<n-1-i;j++){
        yield {type:'compare',i:j,j:j+1};
        if(a[j] > a[j+1]){
          yield {type:'swap',i:j,j:j+1};
          let tmp = a[j]; a[j]=a[j+1]; a[j+1]=tmp;
          swapped = true;
        }
        if(stepMode) yield {type:'yield'};
      }
      yield {type:'markSorted',index:n-1-i};
      if(!swapped) break;
    }
    // mark remaining as sorted
    for(let k=0;k<n;k++) yield {type:'markSorted',index:k};
  }

  function* quickSort(a){
    // iterative stack for easier visualization
    let stack = [[0,a.length-1]];
    let active = 0;
    function* partition(lo,hi){
      active++;
      yield {type:'recActive',delta:1};
      if(lo>=hi){ active--; yield {type:'recActive',delta:-1}; return; }
      let pivot = a[hi];
      let i = lo;
      for(let j=lo;j<hi;j++){
        yield {type:'compare',i:j,j:hi};
        if(a[j] < pivot){
          yield {type:'swap',i:i,j:j};
          let t=a[i]; a[i]=a[j]; a[j]=t;
          i++;
        }
        if(stepMode) yield {type:'yield'};
      }
      yield {type:'swap',i:i,j:hi};
      let t=a[i]; a[i]=a[hi]; a[hi]=t;
      yield {type:'partitioned',pivotIndex:i};
      active--; yield {type:'recActive',delta:-1};
      return i;
    }

    // manual recursion using stack but call partition as generator to interleave steps
    while(stack.length){
      let [lo,hi] = stack.pop();
      if(lo>=hi){ continue; }
      // run partition generator
      const pGen = partition(lo,hi);
      let pRes;
      while(true){
        pRes = pGen.next();
        if(pRes.done) break;
        yield pRes.value;
      }
      // pivot index may have been returned via partitioned step; but partition returns pivot index too
      // for safety, find pivot position by scanning for correct pivot (simpler approach): use Lomuto so pivot is at hi originally but moved
      // attempt to deduce pivot index by looking for element that correctly partitions: but we yielded partitioned with i.
      // For correctness, capture pivotIndex from last yielded 'partitioned'
      // We'll rely on that; if missing, fallback to mid.
      let last = null;
      // Unfortunately we cannot inspect yielded history here; instead, let's recompute pivot index by finding location where left<right property holds
      // Simpler: find index k where for all x<k a[x] <= a[k] and for all x>k a[x] >= a[k] (not strict). This is O(n) but acceptable for visualization.
      let pivotIndex = -1;
      for(let k=lo;k<=hi;k++){
        let ok = true;
        for(let x=lo;x<k;x++) if(a[x] > a[k]) { ok=false; break; }
        if(!ok) continue;
        for(let x=k+1;x<=hi;x++) if(a[x] < a[k]) { ok=false; break; }
        if(ok){ pivotIndex = k; break; }
      }
      if(pivotIndex === -1) pivotIndex = Math.floor((lo+hi)/2);
      // push subranges
      // push larger range first to keep stack small
      if(pivotIndex+1 < hi) stack.push([pivotIndex+1, hi]);
      if(lo < pivotIndex-1) stack.push([lo, pivotIndex-1]);
      // mark pivot as sorted candidate (not guaranteed final, but visual cue)
      yield {type:'markSorted',index:pivotIndex};
    }
    for(let k=0;k<a.length;k++) yield {type:'markSorted',index:k};
  }

  function* mergeSort(a){
    // bottom-up iterative merge sort for clear steps
    let n = a.length;
    let width = 1;
    let activeMerges = 0;
    let aux = a.slice();
    while(width < n){
      for(let i=0;i<n;i+=2*width){
        let left = i, mid = Math.min(i+width, n), right = Math.min(i+2*width, n);
        let l = left, r = mid, idx = left;
        activeMerges++;
        yield {type:'mergeActive',delta:1};
        while(l < mid || r < right){
          if(l < mid && r < right){
            yield {type:'compare',i:l,j:r};
            if(a[l] <= a[r]){
              yield {type:'write',index:idx, value:a[l]};
              aux[idx++] = a[l++];
            } else {
              yield {type:'write',index:idx, value:a[r]};
              aux[idx++] = a[r++];
            }
          } else if(l < mid){
            yield {type:'write',index:idx, value:a[l]};
            aux[idx++] = a[l++];
          } else {
            yield {type:'write',index:idx, value:a[r]};
            aux[idx++] = a[r++];
          }
          if(stepMode) yield {type:'yield'};
        }
        // copy back
        for(let k=left;k<right;k++){
          yield {type:'write',index:k, value:aux[k], copyBack:true};
          a[k] = aux[k];
          if(stepMode) yield {type:'yield'};
        }
        activeMerges--;
        yield {type:'mergeActive',delta:-1};
      }
      width *= 2;
    }
    for(let k=0;k<n;k++) yield {type:'markSorted',index:k};
  }

  // Visualization runners for each algorithm
  function Runner(container, array, genFactory, elementsTargets){
    this.array = array.slice();
    this.n = array.length;
    this.container = container;
    this.bars = mkBars(container, this.array);
    this.gen = genFactory(this.array);
    this.comp = 0;
    this.write = 0;
    this.pass = 0;
    this.extra = 0; // recursions or active merges
    this.sortedFlags = new Array(this.n).fill(false);
    this.highlights = {};
  }
  Runner.prototype.reset = function(newArray, genFactory){
    this.array = newArray.slice();
    this.n = newArray.length;
    this.container.innerHTML = '';
    this.bars = mkBars(this.container, this.array);
    this.gen = genFactory(this.array);
    this.comp = 0; this.write = 0; this.pass = 0; this.extra = 0;
    this.sortedFlags = new Array(this.n).fill(false);
    this.highlights = {};
  };
  Runner.prototype.applyStep = function(step, name){
    // step types to handle: compare, swap, write, markSorted, pass, recActive, mergeActive, partitioned, yield
    if(!step) return;
    if(step.type === 'compare'){
      this.comp++;
      this.highlights.current = [step.i];
      this.highlights.compare = [step.j];
    } else if(step.type === 'swap'){
      this.write += 2; // two writes
      let t = this.array[step.i]; this.array[step.i] = this.array[step.j]; this.array[step.j] = t;
      this.highlights.current = [step.i, step.j];
    } else if(step.type === 'write'){
      this.write++;
      this.array[step.index] = step.value;
      this.highlights.current = [step.index];
    } else if(step.type === 'markSorted'){
      this.sortedFlags[step.index] = true;
      this.highlights.sorted = Object.keys(this.sortedFlags).filter(k=>this.sortedFlags[k]).map(Number);
    } else if(step.type === 'pass'){
      this.pass = step.pass;
    } else if(step.type === 'recActive' || step.type === 'mergeActive'){
      this.extra += step.delta;
    } else if(step.type === 'partitioned'){
      // nothing to do other than maybe highlight
      this.highlights.current = [step.pivotIndex];
    } else if(step.type === 'yield'){
      // do nothing special; used to pause optional
    }
    // update visuals
    updateBars(this.bars, this.array, this.highlights);
  };

  // create runners
  let bubbleRunner, quickRunner, mergeRunner;

  function setupRunners(){
    // create fresh copies
    const seedVal = seedInput.value.trim();
    let rand = Math.random;
    if(seedVal !== ''){
      let s = Number(seedVal) || 0;
      rand = rng(s);
    }
    const n = parseInt(sizeSlider.value,10);
    baseArray = createArray(n, preset.value, rand);
    bubbleRunner = new Runner(canvasBubble, baseArray, bubbleSort);
    quickRunner = new Runner(canvasQuick, baseArray, quickSort);
    mergeRunner = new Runner(canvasMerge, baseArray, mergeSort);

    // reset stats display
    bComp.textContent = '0'; bWrite.textContent = '0'; bPass.textContent='0';
    qComp.textContent = '0'; qWrite.textContent = '0'; qRec.textContent='0';
    mComp.textContent = '0'; mWrite.textContent = '0'; mAct.textContent='0';
  }

  setupRunners();

  // step execution
  function runStep(){
    let anyActive = false;

    const runOne = (runner, statsElems, name) => {
      let res = runner.gen.next();
      if(res.done) {
        // ensure all marked sorted
        updateBars(runner.bars, runner.array, {sorted:[...Array(runner.n).keys()]});
        return false;
      }
      anyActive = true;
      // apply step
      runner.applyStep(res.value, name);
      // update stats display
      if(name==='bubble'){
        bComp.textContent = runner.comp;
        bWrite.textContent = runner.write;
        bPass.textContent = runner.pass;
      } else if(name==='quick'){
        qComp.textContent = runner.comp;
        qWrite.textContent = runner.write;
        qRec.textContent = runner.extra;
      } else if(name==='merge'){
        mComp.textContent = runner.comp;
        mWrite.textContent = runner.write;
        mAct.textContent = runner.extra;
      }
      return true;
    };

    const b = runOne(bubbleRunner, null, 'bubble');
    const q = runOne(quickRunner, null, 'quick');
    const m = runOne(mergeRunner, null, 'merge');

    // if in stepMode, pause after one triple-step
    if(stepMode){
      stepRequested = false;
      running = false;
      clearInterval(auto);
      auto = null;
    }

    return anyActive;
  }

  function startAuto(){
    if(running) return;
    running = true;
    speed = parseInt(speedSlider.value,10);
    if(stepMode){
      // just do one step and stop
      runStep();
      running = false;
      return;
    }
    auto = setInterval(()=>{
      const active = runStep();
      if(!active){
        clearInterval(auto); auto=null; running=false;
      }
    }, Math.max(1, speed));
  }

  function pauseAuto(){
    running = false;
    if(auto) { clearInterval(auto); auto=null; }
  }

  // Button events
  startBtn.addEventListener('click', ()=>{
    stepMode = false;
    startAuto();
  });
  pauseBtn.addEventListener('click', ()=>{
    pauseAuto();
  });
  resetBtn.addEventListener('click', ()=>{
    pauseAuto();
    setupRunners();
  });
  stepBtn.addEventListener('click', ()=>{
    if(!running){
      stepMode = true;
      runStep();
    }
  });

  // react to size/preset/seed changes
  sizeSlider.addEventListener('change', ()=>{ pauseAuto(); setupRunners(); });
  preset.addEventListener('change', ()=>{ pauseAuto(); setupRunners(); });
  seedInput.addEventListener('change', ()=>{ pauseAuto(); setupRunners(); });
  speedSlider.addEventListener('change', ()=>{ if(running){ pauseAuto(); startAuto(); } });

  // initialize visuals
  setupRunners();

  // optionally start automatically
  // startAuto();
})();
</script>
</body>
