      <h2>Merge Sort <span class="small">(O(n log n))</span></h2>
      <div class="canvas"><div class="bars" id="mergeBars"></div></div>
      <div class="stats">
        <div class="stat">Comparisons: <span id="mergeComps">0</span></div>
        <div class="stat">Assignments: <span id="mergeSwaps">0</span></div>
      </div>
    </div>
  </div>

  <div class="footer">
    <div class="explain">
      Brief explanation:
      <ul>
        <li>Bubble Sort repeatedly compares adjacent items and swaps them if out of order. It is simple but inefficient for large arrays: worst-case and average time O(n^2).</li>
        <li>Quick Sort picks a pivot and partitions elements around it, then recursively sorts the partitions. Average time O(n log n); worst-case O(n^2) if pivots are poor (usually mitigated by randomization).</li>
        <li>Merge Sort divides the array in half, recursively sorts halves and merges them. Time is O(n log n) in all cases; it uses extra space for merging.</li>
      </ul>
    </div>
    <div class="credits">Controls: Randomize creates the same initial data for all algorithms. Start runs them in parallel so you can compare steps and speed. Adjust array size and speed to see differences more clearly.</div>
  </div>

  <script>
    // Utility: create initial array
    const sizeInput = document.getElementById('size');
    const sizeLabel = document.getElementById('sizeLabel');
    const speedInput = document.getElementById('speed');
    const speedLabel = document.getElementById('speedLabel');
    const randBtn = document.getElementById('randBtn');
    const startBtn = document.getElementById('startBtn');
    const stopBtn = document.getElementById('stopBtn');

    const bubbleBars = document.getElementById('bubbleBars');
    const quickBars = document.getElementById('quickBars');
    const mergeBars = document.getElementById('mergeBars');

    const bubbleComps = document.getElementById('bubbleComps');
    const bubbleSwaps = document.getElementById('bubbleSwaps');
    const quickComps = document.getElementById('quickComps');
    const quickSwaps = document.getElementById('quickSwaps');
    const mergeComps = document.getElementById('mergeComps');
    const mergeSwaps = document.getElementById('mergeSwaps');

    let baseArray = [];
    let running = false;
    let animSpeed = 1; // multiplier: higher is faster

    function randArray(n) {
      const arr = [];
      for (let i = 0; i < n; i++) arr.push(Math.random());
      return arr;
    }

    function renderBars(container, array) {
      container.innerHTML = '';
      const n = array.length;
      for (let i = 0; i < n; i++) {
        const div = document.createElement('div');
        div.className = 'bar';
        div.style.height = (array[i] * 100) + '%';
        div.dataset.index = i;
        container.appendChild(div);
      }
    }

    function updateBarHeights(container, array) {
      const bars = container.children;
      for (let i = 0; i < array.length; i++) {
        bars[i].style.height = (array[i] * 100) + '%';
      }
    }

    function clearHighlights(container) {
      const bars = container.children;
      for (let b of bars) {
        b.classList.remove('compare', 'swap', 'sorted');
      }
    }

    // Algorithm runners: each yields actions that the animator will consume.
    // Actions: {type: 'compare'|'swap'|'assign'|'markSorted', indices: [...]}
    function* bubbleSortGen(arr) {
      const a = arr.slice();
      const n = a.length;
      let comps = 0, swaps = 0;
      for (let i = 0; i < n; i++) {
        let swapped = false;
        for (let j = 0; j < n - 1 - i; j++) {
          comps++; yield {type: 'compare', indices: [j, j+1], comps, swaps};
          if (a[j] > a[j+1]) {
            swaps++; [a[j], a[j+1]] = [a[j+1], a[j]];
            swapped = true;
            yield {type: 'swap', indices: [j, j+1], comps, swaps, array: a.slice()};
          }
        }
        yield {type: 'markSorted', index: n-1-i, array: a.slice(), comps, swaps};
        if (!swapped) break;
      }
      // mark remaining sorted
      for (let k = 0; k < n; k++) yield {type:'markSortedAll', array: a.slice(), comps, swaps};
    }

    function* quickSortGen(arr) {
      const a = arr.slice();
      const n = a.length;
      let comps = 0, swaps = 0;
      // iterative stack to allow yielding
      const stack = [[0, n-1]];
      const bars = a;
      while (stack.length) {
        const [l, r] = stack.pop();
        if (l >= r) {
          if (l === r) yield {type:'markSorted', index: l, array: bars.slice(), comps, swaps};
          continue;
        }
        // choose pivot as middle
        const p = Math.floor((l + r) / 2);
        const pivot = bars[p];
        // move pivot to end
        swaps++; [bars[p], bars[r]] = [bars[r], bars[p]];
        yield {type:'swap', indices:[p, r], array: bars.slice(), comps, swaps};
        let store = l;
        for (let i = l; i < r; i++) {
          comps++; yield {type:'compare', indices:[i, r], array: bars.slice(), comps, swaps};
          if (bars[i] < pivot) {
            swaps++; [bars[i], bars[store]] = [bars[store], bars[i]];
            yield {type:'swap', indices:[i, store], array: bars.slice(), comps, swaps};
            store++;
          }
        }
        // move pivot to its final place
        swaps++; [bars[store], bars[r]] = [bars[r], bars[store]];
        yield {type:'swap', indices:[store, r], array: bars.slice(), comps, swaps};
        // pivot at store is in final position
        yield {type:'markSorted', index: store, array: bars.slice(), comps, swaps};
        // push subproblems (larger first so smaller sorts sooner visually)
        if (store - 1 - l > r - (store + 1)) {
          if (l < store - 1) stack.push([l, store - 1]);
          if (store + 1 < r) stack.push([store + 1, r]);
        } else {
          if (store + 1 < r) stack.push([store + 1, r]);
          if (l < store - 1) stack.push([l, store - 1]);
        }
      }
      // final mark
      for (let k = 0; k < n; k++) yield {type:'markSortedAll', array: bars.slice(), comps, swaps};
    }

    function* mergeSortGen(arr) {
      const a = arr.slice();
      const n = a.length;
      let comps = 0, assigns = 0;
      // bottom-up iterative merge sort to yield during merges
      let width = 1;
      while (width < n) {
        for (let i = 0; i < n; i += 2*width) {
          const left = i;
          const mid = Math.min(i + width, n);
          const right = Math.min(i + 2*width, n);
          // merge [left, mid) and [mid, right)
          let l = left, r = mid;
          const temp = [];
          while (l < mid && r < right) {
            comps++; yield {type:'compare', indices:[l, r], array: a.slice(), comps, assigns};
            if (a[l] <= a[r]) {
              temp.push(a[l++]);
            } else {
              temp.push(a[r++]);
            }
          }
          while (l < mid) temp.push(a[l++]);
          while (r < right) temp.push(a[r++]);
          // write back with assignment yields for visualization
          for (let k = 0; k < temp.length; k++) {
            a[left + k] = temp[k];
            assigns++; yield {type:'assign', indices:[left+k], array: a.slice(), comps, assigns};
          }
        }
        width *= 2;
      }
      for (let k = 0; k < n; k++) yield {type:'markSortedAll', array: a.slice(), comps, assigns};
    }

    // Animator: consumes generator actions and updates UI
    function runGenerator(gen, container, compsEl, swapsEl, role) {
      let lastArray = baseArray.slice();
      const bars = container;
      let genObj = gen(lastArray);
      let stopped = false;

      function resetDisplay() {
        updateBarHeights(bars, lastArray);
        clearHighlights(bars);
        const b = bars.children;
        for (let i = 0; i < b.length; i++) b[i].classList.remove('sorted');
        compsEl.textContent = '0';
        swapsEl.textContent = '0';
      }

      resetDisplay();

      function step() {
        if (stopped || !running) return;
        const res = genObj.next();
        if (res.done) {
          // mark all sorted visually
          const b = bars.children;
          for (let i = 0; i < b.length; i++) {
            b[i].classList.add('sorted');
          }
          return;
        }
        const act = res.value;
        // update counters and visuals based on type
        if (act.type === 'compare') {
          clearHighlights(bars);
          const [i,j] = act.indices;
          const b = bars.children;
          if (b[i]) b[i].classList.add('compare');
          if (b[j]) b[j].classList.add('compare');
          compsEl.textContent = act.comps;
        } else if (act.type === 'swap') {
          clearHighlights(bars);
          const [i,j] = act.indices;
          const b = bars.children;
          if (b[i]) b[i].classList.add('swap');
          if (b[j]) b[j].classList.add('swap');
          if (act.array) { updateBarHeights(bars, act.array); lastArray = act.array.slice(); }
          compsEl.textContent = act.comps || compsEl.textContent;
          swapsEl.textContent = act.swaps || act.assigns || swapsEl.textContent;
        } else if (act.type === 'assign') {
          clearHighlights(bars);
          const [i] = act.indices;
          const b = bars.children;
          if (b[i]) b[i].classList.add('swap');
          if (act.array) { updateBarHeights(bars, act.array); lastArray = act.array.slice(); }
          compsEl.textContent = act.comps || compsEl.textContent;
          swapsEl.textContent = act.assigns || swapsEl.textContent;
        } else if (act.type === 'markSorted') {
          clearHighlights(bars);
          const idx = act.index;
          const b = bars.children;
          if (b[idx]) b[idx].classList.add('sorted');
          if (act.array) { updateBarHeights(bars, act.array); lastArray = act.array.slice(); }
          compsEl.textContent = act.comps || compsEl.textContent;
          swapsEl.textContent = act.swaps || act.assigns || swapsEl.textContent;
        } else if (act.type === 'markSortedAll') {
          clearHighlights(bars);
          if (act.array) { updateBarHeights(bars, act.array); lastArray = act.array.slice(); }
          const b = bars.children;
          for (let i = 0; i < b.length; i++) b[i].classList.add('sorted');
          compsEl.textContent = act.comps || compsEl.textContent;
          swapsEl.textContent = act.swaps || act.assigns || swapsEl.textContent;
        }

        // schedule next step based on speed
        const baseDelay = 200; // ms per step at speed 1
        const delay = Math.max(8, baseDelay / (animSpeed));
        setTimeout(step, delay);
      }

      // return control object to stop or reset
      step();
      return {stop: () => { stopped = true; }};
    }

    let runners = [];

    function startAll() {
      if (running) return;
      running = true;
      startBtn.disabled = true;
      stopBtn.disabled = false;
      randBtn.disabled = true;
      sizeInput.disabled = true;
      speedInput.disabled = true;

      // render initial bars
      renderBars(bubbleBars, baseArray);
      renderBars(quickBars, baseArray);
      renderBars(mergeBars, baseArray);

      bubbleComps.textContent = '0'; bubbleSwaps.textContent = '0';
      quickComps.textContent = '0'; quickSwaps.textContent = '0';
      mergeComps.textContent = '0'; mergeSwaps.textContent = '0';

      // create runners
      const bRunner = runGenerator(bubbleSortGen, bubbleBars, bubbleComps, bubbleSwaps, 'bubble');
      const qRunner = runGenerator(quickSortGen, quickBars, quickComps, quickSwaps, 'quick');
      const mRunner = runGenerator(mergeSortGen, mergeBars, mergeComps, mergeSwaps, 'merge');
      runners = [bRunner, qRunner, mRunner];
    }

    function stopAll() {
      running = false;
      startBtn.disabled = false;
      stopBtn.disabled = true;
      randBtn.disabled = false;
      sizeInput.disabled = false;
      speedInput.disabled = false;
      // stop generators
      for (const r of runners) if (r && r.stop) r.stop();
      runners = [];
    }

    function createAndRender() {
      baseArray = randArray(+sizeInput.value);
      renderBars(bubbleBars, baseArray);
      renderBars(quickBars, baseArray);
      renderBars(mergeBars, baseArray);
      bubbleComps.textContent = '0'; bubbleSwaps.textContent = '0';
      quickComps.textContent = '0'; quickSwaps.textContent = '0';
      mergeComps.textContent = '0'; mergeSwaps.textContent = '0';
    }

    // UI events
    sizeInput.addEventListener('input', () => {
      sizeLabel.textContent = sizeInput.value;
      if (!running) createAndRender();
    });
    speedInput.addEventListener('input', () => {
      animSpeed = parseFloat(speedInput.value);
      speedLabel.textContent = animSpeed + 'x';
    });
    randBtn.addEventListener('click', () => {
      if (running) return;
      createAndRender();
    });
    startBtn.addEventListener('click', () => {
      if (running) return;
      startAll();
    });
    stopBtn.addEventListener('click', () => {
      stopAll();
    });

    // initialize
    sizeLabel.textContent = sizeInput.value;
    speedLabel.textContent = speedInput.value + 'x';
    animSpeed = parseFloat(speedInput.value);
    createAndRender();
  </script>
</body>
</html>
