(function(){
  // Configuration
  const ANIMATION_DELAY_DEFAULT = 60; // ms
  let ANIMATION_DELAY = ANIMATION_DELAY_DEFAULT;

  // DOM refs
  const sizeRange = document.getElementById('sizeRange');
  const sizeLabel = document.getElementById('sizeLabel');
  const delayRange = document.getElementById('delayRange');
  const delayLabel = document.getElementById('delayLabel');
  const shuffleBtn = document.getElementById('shuffleBtn');
  const startBtn = document.getElementById('startBtn');
  const stopBtn = document.getElementById('stopBtn');

  const bubbleBars = document.getElementById('bubbleBars');
  const quickBars = document.getElementById('quickBars');
  const mergeBars = document.getElementById('mergeBars');

  const bubbleStepsEl = document.getElementById('bubbleSteps');
  const quickStepsEl = document.getElementById('quickSteps');
  const mergeStepsEl = document.getElementById('mergeSteps');

  const bubbleState = document.getElementById('bubbleState');
  const quickState = document.getElementById('quickState');
  const mergeState = document.getElementById('mergeState');

  let size = parseInt(sizeRange.value,10);
  let array = [];
  let running = false;
  let controllers = [];

  sizeLabel.textContent = size;
  delayLabel.textContent = ANIMATION_DELAY;

  sizeRange.addEventListener('input', ()=>{
    size = parseInt(sizeRange.value,10);
    sizeLabel.textContent = size;
    resetAll();
  });
  delayRange.addEventListener('input', ()=>{
    ANIMATION_DELAY = parseInt(delayRange.value,10);
    delayLabel.textContent = ANIMATION_DELAY;
  });

  shuffleBtn.addEventListener('click', resetAll);
  startBtn.addEventListener('click', startAll);
  stopBtn.addEventListener('click', stopAll);

  function resetAll(){
    stopAll();
    array = makeRandomArray(size);
    renderArrays();
    bubbleStepsEl.textContent = '0';
    quickStepsEl.textContent = '0';
    mergeStepsEl.textContent = '0';
    bubbleState.textContent = 'Idle';
    quickState.textContent = 'Idle';
    mergeState.textContent = 'Idle';
  }

  function makeRandomArray(n){
    const a = [];
    for(let i=0;i<n;i++) a.push(i+1);
    // shuffle
    for(let i=a.length-1;i>0;i--){
      const j = Math.floor(Math.random()*(i+1));
      [a[i], a[j]] = [a[j], a[i]];
    }
    return a;
  }

  function renderArrays(){
    const widths = getBarWidths(size);
    clearChildren(bubbleBars); clearChildren(quickBars); clearChildren(mergeBars);
    for(let i=0;i<array.length;i++){
      const v = array[i];
      const bh = valueToHeight(v, array.length);
      const b1 = document.createElement('div');
      b1.className = 'bar bubble';
      b1.style.height = bh + '%';
      b1.style.flex = '0 0 ' + widths + 'px';
      bubbleBars.appendChild(b1);

      const b2 = document.createElement('div');
      b2.className = 'bar quick';
      b2.style.height = bh + '%';
