  function clearChildren(el){ while(el.firstChild) el.removeChild(el.firstChild); }

  // Utility to animate swaps and writes
  function swapVisual(barsEl, i, j){
    const bars = barsEl.children;
    if(i<0||j<0||i>=bars.length||j>=bars.length) return;
    const hi = bars[i].style.height;
    const hj = bars[j].style.height;
    bars[i].style.height = hj;
    bars[j].style.height = hi;
    bars[i].style.background = bars[i].className.includes('bubble') ? 'linear-gradient(180deg,#ff9b9b,#ff6b6b)' : '';
    bars[j].style.background = bars[j].className.includes('bubble') ? 'linear-gradient(180deg,#ff9b9b,#ff6b6b)' : '';
    // restore color shortly after
    setTimeout(()=> {
      bars[i].style.background = '';
      bars[j].style.background = '';
    }, ANIMATION_DELAY+10);
  }

  function writeVisual(barsEl, index, valueHeightPercent){
    const bars = barsEl.children;
    if(index<0||index>=bars.length) return;
    bars[index].style.height = valueHeightPercent + '%';
    bars[index].style.background = 'rgba(0,0,0,0.06)';
    setTimeout(()=> { bars[index].style.background = ''; }, ANIMATION_DELAY+10);
  }

  // Sorting generators that yield actions so we can animate them.
  function* bubbleSortGen(arr){
    // operate on a copy to yield operations
    const a = arr.slice();
    let n = a.length;
    let steps = 0;
    let swapped;
    for(let i=0;i<n;i++){
      swapped = false;
      for(let j=0;j<n-1-i;j++){
        steps++;
        yield {type:'compare',i:j,j:j+1,steps};
        if(a[j] > a[j+1]){
          [a[j], a[j+1]] = [a[j+1], a[j]];
          swapped = true;
          steps++;
          yield {type:'swap',i:j,j:j+1,steps};
        }
      }
      if(!swapped) break;
    }
    yield {type:'done',steps};
  }

  function* quickSortGen(arr){
    const a = arr.slice();
    let steps = 0;
    const stack = [[0,a.length-1]];
    // iterative quicksort using stack to yield partition steps
    while(stack.length){
      const [lo, hi] = stack.pop();
      if(lo >= hi) continue;
      // partition
      const pivot = a[hi];
      let p = lo;
      for(let i=lo;i<hi;i++){
        steps++;
        yield {type:'compare',i, j:hi, steps};
        if(a[i] < pivot){
          if(i !== p){
            [a[i], a[p]] = [a[p], a[i]];
            steps++;
            yield {type:'swap',i:i,j:p,steps};
          }
          p++;
        }
      }
      if(p !== hi){
        [a[p], a[hi]] = [a[hi], a[p]];
        steps++;
        yield {type:'swap',i:p,j:hi,steps};
      }
      // push subproblems (larger first so smaller is processed next)
      if(p+1 < hi) stack.push([p+1, hi]);
      if(lo < p-1) stack.push([lo, p-1]);
    }
    yield {type:'done', steps};
  }

  function* mergeSortGen(arr){
    const a = arr.slice();
    let steps = 0;
    // iterative bottom-up merge sort with yielding writes
    const n = a.length;
    let width = 1;
    const aux = a.slice();
    while(width < n){
      let i = 0;
      while(i < n){
        const left = i;
        const mid = Math.min(i + width, n);
        const right = Math.min(i + 2*width, n);
        // merge [left,mid) and [mid,right)
        let l = left, r = mid, k = left;
        while(l < mid || r < right){
          if(l < mid && (r >= right || a[l] <= a[r])){
            aux[k++] = a[l++];
            steps++;
            yield {type:'write',index:k-1, value:aux[k-1], steps};
          } else {
            aux[k++] = a[r++];
            steps++;
            yield {type:'write',index:k-1, value:aux[k-1], steps};
          }
        }
        for(let t = left; t < right; t++){
          a[t] = aux[t];
        }
        i += 2*width;
      }
      width *= 2;
    }
    yield {type:'done', steps};
  }

  // Runner that takes generator and performs visual actions on bars
  function runGenerator(gen, barsEl, stepsEl, stateEl, style){
    let stopped = false;
    const it = gen[Symbol.iterator] ? gen : gen();
    stateEl.textContent = 'Running';
    let lastSteps = 0;
    function nextAction(){
      if(stopped) return;
      const res = it.next();
      if(res.done){
        stateEl.textContent = 'Done';
        return;
      }
      const a = res.value;
      lastSteps = a.steps || lastSteps;
      stepsEl.textContent = lastSteps;
      // perform visuals based on type
      if(a.type === 'compare'){
        // highlight bars quickly then continue
        highlightCompare(barsEl, a.i, a.j);
        setTimeout(nextAction, Math.max(1, ANIMATION_DELAY));
      } else if(a.type === 'swap'){
        swapVisual(barsEl, a.i, a.j);
        setTimeout(nextAction, Math.max(1, ANIMATION_DELAY));
      } else if(a.type === 'write'){
        const h = Math.round(a.value / array.length * 100);
        writeVisual(barsEl, a.index, h);
        setTimeout(nextAction, Math.max(1, ANIMATION_DELAY));
      } else if(a.type === 'done'){
        // ensure final state visually sorted
        finalizeBars(barsEl);
        stateEl.textContent = 'Done';
      } else {
        setTimeout(nextAction, Math.max(1, ANIMATION_DELAY));
      }
    }
    nextAction();
    return {
      stop(){ stopped = true; stateEl.textContent = 'Stopped'; }
    };
  }

  function highlightCompare(barsEl, i, j){
    const bars = barsEl.children;
    if(i>=0 && i<bars.length) bars[i].style.boxShadow = '0 0 0 3px rgba(0,0,0,0.06)';
    if(j>=0 && j<bars.length) bars[j].style.boxShadow = '0 0 0 3px rgba(0,0,0,0.06)';
    setTimeout(()=> {
      if(i>=0 && i<bars.length) bars[i].style.boxShadow = '';
      if(j>=0 && j<bars.length) bars[j].style.boxShadow = '';
    }, ANIMATION_DELAY);
  }

  function finalizeBars(barsEl){
    const bars = barsEl.children;
    for(let i=0;i<bars.length;i++){
      bars[i].style.height = Math.round((i+1)/bars.length*100) + '%';
    }
  }

  // Prepare separate arrays for each algorithm to ensure same values but independent order for their internal arrays
  function startAll(){
    if(running) return;
    running = true;
    startBtn.disabled = true;
    stopBtn.disabled = false;
    shuffleBtn.disabled = true;
    sizeRange.disabled = true;
    delayRange.disabled = true;

    // create clones of initial heights so visuals start same
    // ensure bars show same randomized array values
    renderArrays();

    const initialArray = array.slice();

    // Create generators
    const bubbleGen = bubbleSortGen(initialArray);
    const quickGen = quickSortGen(initialArray);
    const mergeGen = mergeSortGen(initialArray);

    // Run them
    const c1 = runGenerator(bubbleGen, bubbleBars, bubbleStepsEl, bubbleState, 'bubble');
    const c2 = runGenerator(quickGen, quickBars, quickStepsEl, quickState, 'quick');
    const c3 = runGenerator(mergeGen, mergeBars, mergeStepsEl, mergeState, 'merge');
    controllers = [c1,c2,c3];

    // Poll for all done or stopped to re-enable controls
    const monitor = setInterval(()=>{
      if((bubbleState.textContent === 'Done' || bubbleState.textContent === 'Stopped') &&
         (quickState.textContent === 'Done' || quickState.textContent === 'Stopped') &&
         (mergeState.textContent === 'Done' || mergeState.textContent === 'Stopped')){
        clearInterval(monitor);
        running = false;
        startBtn.disabled = false;
        stopBtn.disabled = true;
        shuffleBtn.disabled = false;
        sizeRange.disabled = false;
        delayRange.disabled = false;
      }
    }, 200);
  }

  function stopAll(){
    controllers.forEach(c => { try{ c.stop(); }catch(e){} });
    controllers = [];
    running = false;
    startBtn.disabled = false;
    stopBtn.disabled = true;
    shuffleBtn.disabled = false;
    sizeRange.disabled = false;
    delayRange.disabled = false;
  }

  // Init
  resetAll();

  // Resize handler to re-render bar widths
  window.addEventListener('resize', ()=> { renderArrays(); });

})();
</script>
</body>
