<script>
(() => {
  // Utilities
  const $ = s => document.querySelector(s);
  const $$ = s => Array.from(document.querySelectorAll(s));
  const randInt = (a,b) => Math.floor(Math.random()*(b-a+1))+a;

  // Elements
  const sizeInput = $('#size');
  const speedInput = $('#speed');
  const shuffleBtn = $('#shuffleBtn');
  const playBtn = $('#playBtn');
  const pauseBtn = $('#pauseBtn');
  const resetBtn = $('#resetBtn');

  const barsBubble = $('#bars-bubble');
  const barsQuick = $('#bars-quick');
  const barsMerge = $('#bars-merge');

  const bComps = $('#b-comps'), bSwaps = $('#b-swaps');
  const qComps = $('#q-comps'), qSwaps = $('#q-swaps');
  const mComps = $('#m-comps'), mSwaps = $('#m-swaps');

  let baseArray = [];
  let animSpeed = Number(speedInput.value); // 1..100 (higher = faster)
  let playing = false;
  let animHandles = [];

  function makeArray(n){
    const arr = [];
    for(let i=0;i<n;i++){
      arr.push(i+1);
    }
    // shuffle
    for(let i=n-1;i>0;i--){
      const j = Math.floor(Math.random()*(i+1));
      [arr[i],arr[j]] = [arr[j],arr[i]];
    }
    return arr;
  }

  function createBars(container, arr, cls){
    container.innerHTML = '';
    const n = arr.length;
    for(let i=0;i<n;i++){
      const div = document.createElement('div');
      div.className = 'bar ' + cls;
      div.style.height = (arr[i] / n * 100) + '%';
      div.style.width = (100/n - 0.5) + '%';
      container.appendChild(div);
    }
  }

  function updateBars(container, arr, cls, highlights = {}) {
    const nodes = container.children;
    const n = arr.length;
    for (let i=0;i<n;i++){
      const h = (arr[i]/n*100) + '%';
      const el = nodes[i];
      el.style.height = h;
      // classes
      el.classList.toggle('compare', highlights.compare && highlights.compare.includes(i));
      el.classList.toggle('swap', highlights.swap && highlights.swap.includes(i));
    }
  }

  // Animation queue per panel
  function Animator(container, arr, cls, cmpElem, swapElem) {
    this.arr = arr.slice();
    this.container = container;
    this.cls = cls;
    this.ops = []; // {type:'compare'|'swap'|'assign', i, j, arrSnapshot?}
    this.counters = {comps:0, swaps:0};
    this.playIndex = 0;
    this.timer = null;
    createBars(container, this.arr, cls);
    cmpElem.textContent = '0';
    swapElem.textContent = '0';
  }

  Animator.prototype.enqueueCompare = function(i,j){
    this.counters.comps++;
    this.ops.push({type:'compare',i,j,arr:this.arr.slice()});
  };
  Animator.prototype.enqueueSwap = function(i,j){
    this.counters.swaps++;
    // perform swap on internal array
    [this.arr[i],this.arr[j]] = [this.arr[j],this.arr[i]];
    this.ops.push({type:'swap',i,j,arr:this.arr.slice()});
  };
  Animator.prototype.enqueueAssign = function(i,val){
    this.counters.swaps++; // count assign like a write
    this.arr[i] = val;
    this.ops.push({type:'assign',i,val,arr:this.arr.slice()});
  };

  Animator.prototype.resetPlayback = function(){
    this.playIndex = 0;
    createBars(this.container, this.ops.length?this.ops[0].arr:this.arr, this.cls);
  };

  Animator.prototype.play = function(speed, onDone, cmpElem, swapElem){
    if(this.timer) return;
    const stepDelay = Math.max(2, 220 - speed*2); // ms
    const runStep = () => {
      if (this.playIndex >= this.ops.length) {
        clearInterval(this.timer);
        this.timer = null;
        if(onDone) onDone();
        return;
      }
      const op = this.ops[this.playIndex++];
      updateBars(this.container, op.arr, this.cls, {
        compare: op.type==='compare' ? [op.i,op.j] : [],
        swap: op.type==='swap' ? [op.i,op.j] : (op.type==='assign' ? [op.i] : [])
      });
      if (cmpElem) cmpElem.textContent = this.counters.comps;
      if (swapElem) swapElem.textContent = this.counters.swaps;
    };
    // immediate first step
    runStep();
    this.timer = setInterval(runStep, stepDelay);
  };

  Animator.prototype.pause = function(){
    if(this.timer) {
      clearInterval(this.timer);
      this.timer = null;
    }
  };

  // Sorting algorithm generators that record operations into Animator
  function bubbleSort(arr, anim){
    const n = arr.length;
    const a = arr.slice();
    for(let pass=0; pass<n-1; pass++){
      let swapped = false;
      for(let i=0;i<n-1-pass;i++){
        anim.enqueueCompare(i, i+1);
        if (a[i] > a[i+1]){
          // swap in local array and record
          [a[i],a[i+1]] = [a[i+1],a[i]];
          anim.enqueueSwap(i, i+1);
          swapped = true;
        }
      }
      if (!swapped) break;
    }
  }

  function quickSortDriver(arr, anim){
    const a = arr.slice();
    function partition(lo,hi){
      const pivot = a[hi];
      let i = lo;
      for(let j=lo;j<hi;j++){
        anim.enqueueCompare(j, hi);
        if (a[j] <= pivot){
          if (i!==j){
            [a[i],a[j]] = [a[j],a[i]];
            anim.enqueueSwap(i,j);
          }
          i++;
        }
      }
      if (i!==hi){
        [a[i],a[hi]] = [a[hi],a[i]];
        anim.enqueueSwap(i,hi);
      }
      return i;
    }
    function qs(lo,hi){
      if (lo>=hi) return;
      const p = partition(lo,hi);
      qs(lo,p-1);
      qs(p+1,hi);
    }
    qs(0,a.length-1);
  }

  function mergeSortDriver(arr, anim){
    const a = arr.slice();
    const aux = new Array(a.length);
    function merge(lo, mid, hi){
      let i = lo, j = mid+1, k = lo;
      while(i<=mid && j<=hi){
        anim.enqueueCompare(i,j);
        if (a[i] <= a[j]){
          aux[k++] = a[i++];
          anim.enqueueAssign(k-1, aux[k-1]);
        } else {
          aux[k++] = a[j++];
          anim.enqueueAssign(k-1, aux[k-1]);
        }
      }
      while(i<=mid){
        aux[k++] = a[i++];
        anim.enqueueAssign(k-1, aux[k-1]);
      }
      while(j<=hi){
        aux[k++] = a[j++];
        anim.enqueueAssign(k-1, aux[k-1]);
      }
      for(let t=lo;t<=hi;t++){
        a[t] = aux[t];
        // record final assignment to reflect movement
        anim.enqueueAssign(t, a[t]);
      }
    }
    function ms(lo,hi){
      if (lo>=hi) return;
      const mid = Math.floor((lo+hi)/2);
      ms(lo,mid);
      ms(mid+1,hi);
      merge(lo,mid,hi);
    }
    ms(0,a.length-1);
  }

  // Build animators for the current baseArray
  let animatorBubble, animatorQuick, animatorMerge;

  function buildAnimators(){
    animatorBubble = new Animator(barsBubble, baseArray, 'bubble', bComps, bSwaps);
    animatorQuick  = new Animator(barsQuick,  baseArray, 'quick',  qComps, qSwaps);
    animatorMerge  = new Animator(barsMerge,  baseArray, 'merge',  mComps, mSwaps);

    // Record operations (this may take time for very large sizes; that's intentional)
    // Bubble (slow)
    bubbleSort(baseArray, animatorBubble);
    quickSortDriver(baseArray, animatorQuick);
    mergeSortDriver(baseArray, animatorMerge);

    // Reset displays
    animatorBubble.resetPlayback();
    animatorQuick.resetPlayback();
    animatorMerge.resetPlayback();

    // Update counters immediately (they reflect totals)
    bComps.textContent = animatorBubble.counters.comps;
    bSwaps.textContent = animatorBubble.counters.swaps;
    qComps.textContent = animatorQuick.counters.comps;
    qSwaps.textContent = animatorQuick.counters.swaps;
    mComps.textContent = animatorMerge.counters.comps;
    mSwaps.textContent = animatorMerge.counters.swaps;
  }

  function shuffleAndBuild(){
    const n = Math.max(8, Math.min(500, Number(sizeInput.value)||60));
    baseArray = makeArray(n);
    buildAnimators();
  }

  shuffleBtn.addEventListener('click', () => {
    shuffleAndBuild();
  });

  playBtn.addEventListener('click', () => {
    if (playing) return;
    playing = true;
    // Start playing each animator in parallel
    const speed = Number(speedInput.value);
    // Reset counters display to start real-time updating during playback
    bComps.textContent = 0; bSwaps.textContent = 0;
    qComps.textContent = 0; qSwaps.textContent = 0;
    mComps.textContent = 0; mSwaps.textContent = 0;

    animatorBubble.play(speed, () => {}, bComps, bSwaps);
    animatorQuick.play(speed+20, () => {}, qComps, qSwaps); // quick a bit faster visually
    animatorMerge.play(speed+30, () => {}, mComps, mSwaps);

  });

  pauseBtn.addEventListener('click', () => {
    playing = false;
    animatorBubble.pause();
    animatorQuick.pause();
    animatorMerge.pause();
  });

  resetBtn.addEventListener('click', () => {
    playing = false;
    animatorBubble.pause();
    animatorQuick.pause();
    animatorMerge.pause();
    buildAnimators();
  });

  sizeInput.addEventListener('change', () => {
    const v = Number(sizeInput.value);
    if (isNaN(v) || v<8) sizeInput.value = 8;
    if (v>500) sizeInput.value = 500;
  });

  speedInput.addEventListener('input', () => {
    animSpeed = Number(speedInput.value);
  });

  // Initialize
  shuffleAndBuild();

  // For dramatic demonstration: when size is large, show alert suggestion
  sizeInput.addEventListener('blur', () => {
    if (Number(sizeInput.value) >= 150) {
      // no modal, just hint in console
      console.log('Large size chosen — bubble sort will be painfully slow. Use pause if needed.');
    }
  });
})();
</script>
</body>
</html>
