<script>
(function(){
  // Utilities
  const sleep = ms => new Promise(r => setTimeout(r, ms));

  // DOM refs
  const sizeEl = document.getElementById('size');
  const sizeVal = document.getElementById('sizeVal');
  const speedEl = document.getElementById('speed');
  const speedVal = document.getElementById('speedVal');
  const shuffleBtn = document.getElementById('shuffle');
  const startBtn = document.getElementById('start');
  const pauseBtn = document.getElementById('pause');

  const barsBubble = document.getElementById('bars-bubble');
  const barsMerge = document.getElementById('bars-merge');
  const barsQuick = document.getElementById('bars-quick');

  const stepsBubble = document.getElementById('steps-bubble');
  const swapsBubble = document.getElementById('swaps-bubble');
  const timeBubble = document.getElementById('time-bubble');

  const stepsMerge = document.getElementById('steps-merge');
  const swapsMerge = document.getElementById('swaps-merge');
  const timeMerge = document.getElementById('time-merge');

  const stepsQuick = document.getElementById('steps-quick');
  const swapsQuick = document.getElementById('swaps-quick');
  const timeQuick = document.getElementById('time-quick');

  sizeVal.textContent = sizeEl.value;
  speedVal.textContent = speedEl.value;

  let baseArray = [];
  let running = false;
  let paused = false;
  let controllers = [];

  function randArray(n){
    const a = Array.from({length:n}, (_,i)=>i+1);
    for(let i=a.length-1;i>0;i--){
      const j = Math.floor(Math.random()*(i+1));
      [a[i],a[j]]=[a[j],a[i]];
    }
    return a;
  }

  function buildBars(container, arr, className){
    container.innerHTML = '';
    const max = Math.max(...arr);
    for(let v of arr){
      const bar = document.createElement('div');
      bar.className = 'bar ' + (className||'');
      bar.style.height = Math.max(2, (v/max)*100) + '%';
      container.appendChild(bar);
    }
  }

  function updateBars(container, arr, highlights=[]){
    const bars = container.children;
    const max = Math.max(...arr);
    for(let i=0;i<bars.length;i++){
      bars[i].style.height = Math.max(2, (arr[i]/max)*100) + '%';
      bars[i].classList.toggle('curr', highlights.indexOf(i) !== -1);
    }
  }

  // Animation pacing: speed slider higher => faster animations
  function paceMultiplier(){
    // map speed(1..100) to ms base: lower speed -> bigger ms
    const s = Number(speedEl.value);
    const base = 500 - (s * 4.5); // ~50ms..496ms
    return Math.max(20, base);
  }

  // Sorting algorithm implementations that yield steps for visualization
  async function bubbleSort(arr, onStep, ctrl){
    const n = arr.length;
    let steps=0, swaps=0;
    const start = performance.now();
    for(let i=0;i<n-1;i++){
      let swapped=false;
      for(let j=0;j<n-1-i;j++){
        if(ctrl.stopped) return {steps,swaps,time:(performance.now()-start)/1000};
        while(ctrl.paused) await sleep(60);
        steps++;
        if(onStep) await onStep({type:'compare',i,j,arr,steps,swaps});
        // intentionally slow for dramatic effect
        await sleep(paceMultiplier()*1.8);
        if(arr[j] > arr[j+1]){
          swaps++;
          [arr[j],arr[j+1]]=[arr[j+1],arr[j]];
          swapped=true;
          if(onStep) await onStep({type:'swap',i,j,arr,steps,swaps});
          await sleep(paceMultiplier()*1.6);
        }
      }
      if(!swapped) break;
    }
    return {steps,swaps,time:(performance.now()-start)/1000};
  }

  async function mergeSort(arr, onStep, ctrl){
    let steps=0, accesses=0;
    const start = performance.now();
    async function merge(l, m, r){
      const left = arr.slice(l,m);
      const right = arr.slice(m,r);
      let i=0,j=0,k=l;
      while(i<left.length || j<right.length){
        if(ctrl.stopped) return;
        while(ctrl.paused) await sleep(20);
        steps++; accesses+=2;
        if(j>=right.length || (i<left.length && left[i]<=right[j])){
          arr[k++] = left[i++];
        } else {
          arr[k++] = right[j++];
        }
        if(onStep) await onStep({type:'merge',l,m,r,arr:arr.slice(),steps,accesses});
        await sleep(paceMultiplier()*0.5);
      }
    }
    async function ms(l,r){
      if(r-l<=1) return;
      const m = Math.floor((l+r)/2);
      await ms(l,m);
      await ms(m,r);
      await merge(l,m,r);
    }
    await ms(0,arr.length);
    return {steps,accesses,time:(performance.now()-start)/1000};
  }

  async function quickSort(arr, onStep, ctrl){
    let steps=0, comps=0;
    const start = performance.now();
    async function qs(l,r){
      if(l>=r) return;
      let pivot = arr[Math.floor((l+r)/2)];
      let i=l, j=r;
      while(i<=j){
        if(ctrl.stopped) return;
        while(ctrl.paused) await sleep(20);
        while(arr[i]<pivot){ i++; comps++; steps++; if(onStep) await onStep({type:'compare',i,j,arr:arr.slice(),steps,comps}); }
        while(arr[j]>pivot){ j--; comps++; steps++; if(onStep) await onStep({type:'compare',i,j,arr:arr.slice(),steps,comps}); }
        if(i<=j){
          [arr[i],arr[j]]=[arr[j],arr[i]];
          steps++; if(onStep) await onStep({type:'swap',i,j,arr:arr.slice(),steps,comps});
          i++; j--;
          await sleep(paceMultiplier()*0.6);
        }
      }
      if(l<j) await qs(l,j);
      if(i<r) await qs(i,r);
    }
    await qs(0,arr.length-1);
    return {steps,comps,time:(performance.now()-start)/1000};
  }

  function makeController(){
    return {paused:false,stopped:false};
  }

  async function runAll(){
    // reset
    running = true;
    paused = false;
    controllers.forEach(c=>{c.stopped=true});
    controllers=[];
    const ctrlB = makeController(), ctrlM = makeController(), ctrlQ = makeController();
    controllers.push(ctrlB, ctrlM, ctrlQ);

    // copies
    const aB = baseArray.slice();
    const aM = baseArray.slice();
    const aQ = baseArray.slice();

    // build UI bars
    buildBars(barsBubble, aB, 'bubble');
    buildBars(barsMerge, aM, '');
    buildBars(barsQuick, aQ, '');

    stepsBubble.textContent = '0'; swapsBubble.textContent='0'; timeBubble.textContent='0.000';
    stepsMerge.textContent = '0'; swapsMerge.textContent='0'; timeMerge.textContent='0.000';
    stepsQuick.textContent = '0'; swapsQuick.textContent='0'; timeQuick.textContent='0.000';

    // launch sorts concurrently
    const pB = bubbleSort(aB, async (state)=>{
      // update bubble UI
      stepsBubble.textContent = state.steps;
      swapsBubble.textContent = state.swaps;
      updateBars(barsBubble, state.arr, state.type==='swap' ? [state.j, state.j+1] : [state.j]);
    }, ctrlB).then(res=>{
      timeBubble.textContent = (res && res.time)? res.time.toFixed(3) : '0.000';
      // final highlight: make bubble panel flash to "humiliate" playfully
      const bars = barsBubble.children;
      for(let i=0;i<bars.length;i++){
        bars[i].classList.add('bubble');
      }
      return res;
    });

    const pM = mergeSort(aM, async (state)=>{
      stepsMerge.textContent = state.steps;
      swapsMerge.textContent = state.accesses || 0;
      updateBars(barsMerge, state.arr, []);
      // subtle glow for current merge segment
      // (not tracking indices precisely to keep code compact)
    }, ctrlM).then(res=>{
      timeMerge.textContent = (res && res.time)? res.time.toFixed(3) : '0.000';
      return res;
    });

    const pQ = quickSort(aQ, async (state)=>{
      stepsQuick.textContent = state.steps;
      swapsQuick.textContent = state.comps || 0;
      updateBars(barsQuick, state.arr, (state.type==='swap') ? [state.i,state.j] : []);
    }, ctrlQ).then(res=>{
      timeQuick.textContent = (res && res.time)? res.time.toFixed(3) : '0.000';
      return res;
    });

    // Wait for all or early stop
    await Promise.all([pB,pM,pQ].map(p=>p.catch(()=>null)));
    running=false;
  }

  // Initialize
  function resetAll(){
    baseArray = randArray(Number(sizeEl.value));
    buildBars(barsBubble, baseArray, 'bubble');
    buildBars(barsMerge, baseArray, '');
    buildBars(barsQuick, baseArray, '');
    stepsBubble.textContent = swapsBubble.textContent = timeBubble.textContent = '0';
    stepsMerge.textContent = swapsMerge.textContent = timeMerge.textContent = '0';
    stepsQuick.textContent = swapsQuick.textContent = timeQuick.textContent = '0';
    controllers.forEach(c=>{c.stopped=true});
    controllers=[];
    running=false;
    paused=false;
  }

  // Events
  sizeEl.addEventListener('input', ()=>{
    sizeVal.textContent = sizeEl.value;
  });

  speedEl.addEventListener('input', ()=>{
    speedVal.textContent = speedEl.value;
  });

  shuffleBtn.addEventListener('click', ()=>{ resetAll(); });

  startBtn.addEventListener('click', ()=>{
    if(running){ // toggle resume if paused
      controllers.forEach(c=>c.paused=false);
      paused=false;
    } else {
      runAll();
    }
  });

  pauseBtn.addEventListener('click', ()=>{
    if(!running) return;
    controllers.forEach(c=>c.paused=true);
    paused=true;
  });

  // Initial
  resetAll();

})();
</script>
</body>
