  .bar.swap{background:linear-gradient(180deg,#ff9a9e,#ff6b6b)}
  .bar.done{background:linear-gradient(180deg,var(--good),#2ec06d)}
  .metrics{display:flex;gap:8px;flex-wrap:wrap;margin-top:8px;font-size:13px;color:var(--muted)}
  .metric{background:rgba(255,255,255,0.02);padding:6px 8px;border-radius:8px}
  .notes{margin-top:10px;color:var(--muted);font-size:13px}
  .footer{display:flex;align-items:center;gap:12px;margin-top:16px;color:var(--muted);font-size:13px}
  .speed{display:flex;gap:8px;align-items:center}
  .note-bubble{background:#08202c;padding:6px 8px;border-radius:8px;color:var(--muted);font-size:12px}
  .humiliate{display:flex;align-items:center;gap:8px;color:var(--danger);font-weight:700}
  .big-time{font-size:18px;color:var(--accent);font-weight:700}
  .beat{color:var(--good);font-weight:700}
  .legend{display:flex;gap:10px;align-items:center;margin-top:8px}
  .legend span{display:inline-flex;gap:6px;align-items:center}
  .legend .sw{width:16px;height:10px;border-radius:3px;display:inline-block}
  /* responsiveness */
  @media (max-width:900px){.bar-area{height:180px}}
  @media (max-width:640px){
    header{flex-direction:column;align-items:flex-start}
    .boards{flex-direction:column}
  }
</style>
</head>
<body>
<div class="wrap">
  <header>
    <div>
      <h1>Sorting Showdown — Bubble Sort vs Faster Algorithms</h1>
      <p class="lead">Same input array is fed to three algorithms. Watch bubble sort lag while QuickSort and MergeSort finish much faster. Step counters, comparisons, swaps and complexity notes included.</p>
    </div>
    <div class="controls">
      <button id="randBtn" class="btn">New Random Array</button>
      <label style="color:var(--muted);font-size:13px">Size:
        <input id="sizeInput" type="range" min="10" max="80" value="30" style="vertical-align:middle;margin-left:8px"/>
      </label>
      <label style="color:var(--muted);font-size:13px">Speed:
        <input id="speedInput" type="range" min="1" max="1000" value="120" style="vertical-align:middle;margin-left:8px"/>
      </label>
      <button id="runBtn" class="btn">Run</button>
      <button id="stopBtn" class="btn secondary">Stop</button>
    </div>
  </header>

  <div class="boards">
    <div class="panel" id="bubblePanel">
      <h2>Bubble Sort <span style="font-size:12px;color:var(--muted)"> (O(n^2) — In-place, stable)</span></h2>
      <div class="controls">
        <div class="note-bubble">Deliberately slowed to dramatize inefficiency</div>
        <div class="humiliate" style="margin-left:auto"><div style="font-size:12px">Status:</div><div id="bubbleStatus" style="padding:6px 8px;border-radius:6px;background:rgba(255,255,255,0.02)">idle</div></div>
      </div>
      <div class="bar-area" id="bubbleArea"></div>
      <div class="metrics">
        <div class="metric">Steps: <span id="bubbleSteps">0</span></div>
        <div class="metric">Comparisons: <span id="bubbleComps">0</span></div>
        <div class="metric">Swaps: <span id="bubbleSwaps">0</span></div>
        <div class="metric">Elapsed: <span id="bubbleTime">0.000</span>s</div>
      </div>
      <div class="notes">
        Worst: O(n^2) • Average: O(n^2) • Best: O(n) (already sorted) • Space: O(1)
      </div>
    </div>

    <div class="panel" id="quickPanel">
      <h2>Quick Sort <span style="font-size:12px;color:var(--muted)"> (Average O(n log n))</span></h2>
      <div class="controls">
        <div class="note-bubble">Typical fast in-memory sort</div>
        <div style="margin-left:auto" class="big-time">Finish: <span id="quickFinish">--</span></div>
      </div>
      <div class="bar-area" id="quickArea"></div>
      <div class="metrics">
        <div class="metric">Steps: <span id="quickSteps">0</span></div>
        <div class="metric">Comparisons: <span id="quickComps">0</span></div>
        <div class="metric">Swaps: <span id="quickSwaps">0</span></div>
        <div class="metric">Elapsed: <span id="quickTime">0.000</span>s</div>
      </div>
      <div class="notes">
        Average: O(n log n) • Worst: O(n^2) (bad pivot) • Space: O(log n) (recursion)
      </div>
    </div>

    <div class="panel" id="mergePanel">
      <h2>Merge Sort <span style="font-size:12px;color:var(--muted)"> (O(n log n) stable)</span></h2>
      <div class="controls">
        <div class="note-bubble">Predictable divide-and-conquer</div>
        <div style="margin-left:auto" class="beat">Finish: <span id="mergeFinish">--</span></div>
      </div>
      <div class="bar-area" id="mergeArea"></div>
      <div class="metrics">
        <div class="metric">Steps: <span id="mergeSteps">0</span></div>
        <div class="metric">Comparisons: <span id="mergeComps">0</span></div>
        <div class="metric">Swaps: <span id="mergeSwaps">0</span></div>
        <div class="metric">Elapsed: <span id="mergeTime">0.000</span>s</div>
      </div>
      <div class="notes">
        Worst/Average/Best: O(n log n) • Space: O(n)
      </div>
    </div>
  </div>

  <div class="footer">
    <div class="legend">
      <span><i class="sw" style="background:linear-gradient(180deg,#3aa0ff,#2b6cb0)"></i> Default</span>
      <span><i class="sw" style="background:linear-gradient(180deg,#ffd86b,#ffb347)"></i> Comparing</span>
      <span><i class="sw" style="background:linear-gradient(180deg,#ff9a9e,#ff6b6b)"></i> Swapping</span>
      <span><i class="sw" style="background:linear-gradient(180deg,var(--good),#2ec06d)"></i> Done</span>
    </div>
    <div style="margin-left:auto">
      <div class="note-bubble">After run, the UI shows how much faster the faster algorithms completed compared to bubble sort.</div>
    </div>
  </div>
</div>

<script>
(function(){
  // Utilities
  function $(id){return document.getElementById(id)}
  const bubbleArea=$('bubbleArea'), quickArea=$('quickArea'), mergeArea=$('mergeArea');
  const sizeInput=$('sizeInput'), speedInput=$('speedInput'), randBtn=$('randBtn');
  const runBtn=$('runBtn'), stopBtn=$('stopBtn');
  let SIZE = +sizeInput.value;
  let BASE_DELAY = 120; // ms baseline
  let arrayMaster = [];
  let running = false;
  let controllers = [];

  function randArray(n){
    const a = [];
    for(let i=0;i<n;i++) a.push(Math.floor(Math.random()*100)+1);
    return a;
  }

  function makeBars(area, arr){
    area.innerHTML='';
    const max = Math.max(...arr);
    for(let i=0;i<arr.length;i++){
      const b = document.createElement('div');
      b.className = 'bar';
      b.style.height = (arr[i]/max*100)+'%';
      b.dataset.value = arr[i];
      b.title = String(arr[i]);
      area.appendChild(b);
    }
  }

  function copyArray(a){ return a.slice(); }

  function updateBar(area, idx, val, cls){
    const bars = area.children;
    if(!bars[idx]) return;
    bars[idx].style.height = val + '%';
    bars[idx].dataset.value = val;
    if(cls){
      bars[idx].classList.add(cls);
      setTimeout(()=>bars[idx].classList.remove(cls), 200);
    }
  }

  function colorize(area, idx, cls){
    const b = area.children[idx];
    if(!b) return;
    b.classList.add(cls);
    setTimeout(()=>b.classList.remove(cls), 200);
  }

  function setDone(area){
    for(const b of area.children) b.classList.add('done');
  }

  function setStatus(id,text){ $(id).textContent=text; }

  function sleep(ms){ return new Promise(r=>setTimeout(r, ms)); }

  // Algorithm implementations that report to UI via callbacks
  async function bubbleSort(arr, area, stats){
    const n = arr.length;
    let comps=0, swaps=0, steps=0;
    const start = performance.now();
    setStatus('bubbleStatus','running');
    for(let i=0;i<n;i++){
      let swapped=false;
      for(let j=0;j<n-1-i;j++){
        comps++; steps++;
        stats.onCompare(j,j+1);
        updateCounters();
        await sleep(BASE_DELAY*4); // deliberately slow and dramatic
        if(arr[j] > arr[j+1]){
          swaps++;
          stats.onSwap(j,j+1);
          const tmp=arr[j]; arr[j]=arr[j+1]; arr[j+1]=tmp;
          // update bars heights (normalized later)
          rebuildBarsFromArray(area, arr);
          await sleep(BASE_DELAY*3);
          swapped=true;
        }
        if(!running) return finish(false);
      }
      if(!swapped) break;
    }
    finish(true);

    function finish(ok){
      const elapsed = (performance.now()-start)/1000;
      stats.onFinished(elapsed, comps, swaps, steps);
      setDone(area);
      setStatus('bubbleStatus', 'done');
      return ok;
    }

    function updateCounters(){
      $('bubbleSteps').textContent = steps;
      $('bubbleComps').textContent = comps;
      $('bubbleSwaps').textContent = swaps;
    }
  }

  async function quickSortDriver(arr, area, stats){
    let comps=0, swaps=0, steps=0;
    const start = performance.now();
    await quickSort(arr,0,arr.length-1);
    const elapsed = (performance.now()-start)/1000;
    stats.onFinished(elapsed, comps, swaps, steps);
    setDone(area);
    $('quickFinish').textContent = elapsed.toFixed(3)+'s';

    async function quickSort(a,l,r){
      if(l>=r) return;
      const p = await partition(a,l,r);
      if(!running) return;
      await Promise.all([quickSort(a,l,p-1), quickSort(a,p+1,r)]);
    }

    async function partition(a,l,r){
      const pivot = a[r];
      let i = l;
      for(let j=l;j<r;j++){
        comps++; steps++;
        stats.onCompare(j,r);
        await sleep(BASE_DELAY* (900/Math.max(1, +speedInput.value))); // faster than bubble
        if(a[j] < pivot){
          swaps++;
          [a[i],a[j]]=[a[j],a[i]];
          rebuildBarsFromArray(area,a);
          stats.onSwap(i,j);
          await sleep(BASE_DELAY* (700/Math.max(1, +speedInput.value)));
          i++;
        }
        if(!running) return;
      }
      [a[i],a[r]]=[a[r],a[i]];
      swaps++;
      rebuildBarsFromArray(area,a);
      stats.onSwap(i,r);
      await sleep(BASE_DELAY*(600/Math.max(1, +speedInput.value)));
      return i;
    }
  }

  async function mergeSortDriver(arr, area, stats){
    let comps=0, swaps=0, steps=0;
    const start = performance.now();
    await mergeSort(arr,0,arr.length-1);
    const elapsed = (performance.now()-start)/1000;
    stats.onFinished(elapsed, comps, swaps, steps);
    setDone(area);
    $('mergeFinish').textContent = elapsed.toFixed(3)+'s';

    async function mergeSort(a,l,r){
      if(l>=r) return;
      const m = Math.floor((l+r)/2);
      await mergeSort(a,l,m);
      await mergeSort(a,m+1,r);
      await merge(a,l,m,r);
    }

    async function merge(a,l,m,r){
      const left = a.slice(l,m+1);
      const right = a.slice(m+1,r+1);
      let i=0,j=0,k=l;
      while(i<left.length && j<right.length){
        steps++; comps++;
        stats.onCompare(l+i,m+1+j);
        await sleep(BASE_DELAY*(400/Math.max(1, +speedInput.value)));
        if(left[i] <= right[j]){
          a[k++] = left[i++];
        }else{
          a[k++] = right[j++];
        }
        rebuildBarsFromArray(area,a);
        await sleep(BASE_DELAY*(300/Math.max(1, +speedInput.value)));
        if(!running) return;
      }
      while(i<left.length){ a[k++]=left[i++]; rebuildBarsFromArray(area,a); await sleep(1); }
      while(j<right.length){ a[k++]=right[j++]; rebuildBarsFromArray(area,a); await sleep(1); }
    }
  }

  function rebuildBarsFromArray(area, arr){
    // normalize to percentage heights relative to max of master
    const max = Math.max(...arrayMaster);
    const bars = area.children;
    for(let i=0;i<arr.length;i++){
      const val = Math.round(arr[i]/max*100);
      if(bars[i]) bars[i].style.height = val+'%';
      bars[i].title = String(arr[i]);
    }
  }

  // Wiring UI
  function generateAndRender(){
    SIZE = +sizeInput.value;
    arrayMaster = randArray(SIZE);
    makeBars(bubbleArea, arrayMaster);
    makeBars(quickArea, arrayMaster);
    makeBars(mergeArea, arrayMaster);
    // reset metrics
    ['bubble','quick','merge'].forEach(pref=>{
      $(pref+'Steps').textContent='0';
      $(pref+'Comps').textContent='0';
      $(pref+'Swaps').textContent='0';
      $(pref+'Time').textContent='0.000';
    });
    $('bubbleTime').textContent='0.000';
    $('quickTime').textContent='0.000';
    $('mergeTime').textContent='0.000';
    $('bubbleStatus').textContent='idle';
    $('quickFinish').textContent='--';
    $('mergeFinish').textContent='--';
  }

  randBtn.addEventListener('click', ()=>{ if(running) return; generateAndRender(); });
  sizeInput.addEventListener('input', ()=>{ if(running) return; generateAndRender(); });

  runBtn.addEventListener('click', async ()=>{
    if(running) return;
    running=true;
    BASE_DELAY = 1000 / Math.max(1, +speedInput.value); // inversely proportional
    // clone arrays
    const a1 = copyArray(arrayMaster);
    const a2 = copyArray(arrayMaster);
    const a3 = copyArray(arrayMaster);

    // stats connectors
    const bubbleStats = {
      onCompare(i,j){ $('bubbleComps').textContent = (+$('bubbleComps').textContent||0)+1; colorize(bubbleArea,i,'compare'); colorize(bubbleArea,j,'compare'); },
      onSwap(i,j){ $('bubbleSwaps').textContent = (+$('bubbleSwaps').textContent||0)+1; colorize(bubbleArea,i,'swap'); colorize(bubbleArea,j,'swap'); },
      onFinished(elapsed, comps, swaps, steps){
        $('bubbleTime').textContent = elapsed.toFixed(3);
        // if others finished earlier, show humiliation ratio
        const q = parseFloat($('quickTime').textContent) || null;
        const m = parseFloat($('mergeTime').textContent) || null;
        const others = [q,m].filter(x=>x);
        if(others.length){
          const best = Math.min(...others);
          const diff = elapsed / best;
          if(diff>1.05){
            // show dramatic message
            $('bubbleStatus').textContent = 'slaughtered';
            setTimeout(()=>alert('Bubble sort took '+elapsed.toFixed(3)+'s — about '+diff.toFixed(2)+'× slower than the quickest algorithm.'), 50);
          } else {
            $('bubbleStatus').textContent = 'done';
          }
        } else {
          $('bubbleStatus').textContent = 'done';
        }
      }
    };
    const quickStats = {
      onCompare(i,j){ $('quickComps').textContent = (+$('quickComps').textContent||0)+1; colorize(quickArea,i,'compare'); colorize(quickArea,j,'compare'); },
      onSwap(i,j){ $('quickSwaps').textContent = (+$('quickSwaps').textContent||0)+1; colorize(quickArea,i,'swap'); colorize(quickArea,j,'swap'); },
      onFinished(elapsed, comps, swaps, steps){
        $('quickTime').textContent = elapsed.toFixed(3);
        $('quickSteps').textContent = steps;
        // compare with bubble if done
        const b = parseFloat($('bubbleTime').textContent) || null;
        if(b){
          const ratio = b/elapsed;
          // show beat value
        }
      }
    };
    const mergeStats = {
      onCompare(i,j){ $('mergeComps').textContent = (+$('mergeComps').textContent||0)+1; colorize(mergeArea,i,'compare'); colorize(mergeArea,j,'compare'); },
      onSwap(i,j){ $('mergeSwaps').textContent = (+$('mergeSwaps').textContent||0)+1; colorize(mergeArea,i,'swap'); colorize(mergeArea,j,'swap'); },
      onFinished(elapsed, comps, swaps, steps){
        $('mergeTime').textContent = elapsed.toFixed(3);
        $('mergeSteps').textContent = steps;
      }
    };

    // start async tasks
    controllers = [
      bubbleSort(a1, bubbleArea, bubbleStats),
      quickSortDriver(a2, quickArea, quickStats),
      mergeSortDriver(a3, mergeArea, mergeStats)
    ];

    // await all (but allow stop)
    await Promise.allSettled(controllers);
    running=false;
    // show final comparative note
    const bt = parseFloat($('bubbleTime').textContent) || Infinity;
    const qt = parseFloat($('quickTime').textContent) || Infinity;
    const mt = parseFloat($('mergeTime').textContent) || Infinity;
    const best = Math.min(qt,mt,bt);
    if(best<Infinity){
      const winner = best===qt ? 'Quick Sort' : best===mt ? 'Merge Sort' : 'Bubble Sort';
      const beatBy = (bt/best).toFixed(2);
      if(winner!=='Bubble Sort'){
        // add visual humiliation: flash bubble panel background quickly
        const panel = $('bubblePanel');
        const orig = panel.style.boxShadow;
        panel.animate([{boxShadow:'0 0 40px rgba(255,80,80,0.9)'},{boxShadow:orig}],{duration:900,iterations:3});
        // display beat text
        setTimeout(()=>{ alert(winner+' won! Bubble sort was ~'+beatBy+'× slower.'); }, 150);
      }
    }
  });

  stopBtn.addEventListener('click', ()=>{
    running=false;
  });

  // init
  generateAndRender();
})();
</script>
</body>
</html>

